#include <omp.h>
#include <stdlib.h>
#include <stdio.h>
#include <string.h>
#include <limits.h>
#include "../common.h"
#include "./kernel_gpu_opencl_wrapper.h"

typedef struct record {
	int value;
} record;

typedef struct knode {
	int location;
	int indices [DEFAULT_ORDER + 1];
	int  keys [DEFAULT_ORDER + 1];
	bool is_leaf;
	int num_keys;
} knode;

void 
kernel_gpu_opencl_wrapper(	record *records,
							long records_mem,
							knode *knodes,
							long knodes_elem,
							long knodes_mem,

							int order,
							long maxheight,
							int count,

							long *currKnode,
							long *offset,
							int *keys,
							record *ans)
{

#ifdef TIMING
	struct timeval tv;
	struct timeval tv_total_start, tv_total_end;
	struct timeval tv_init_end;
	struct timeval tv_h2d_start, tv_h2d_end;
	struct timeval tv_d2h_start, tv_d2h_end;
	struct timeval tv_kernel_start, tv_kernel_end;
	struct timeval tv_mem_alloc_start, tv_mem_alloc_end;
	struct timeval tv_close_start, tv_close_end;
	float init_time = 0, mem_alloc_time = 0, h2d_time = 0, kernel_time= 0,
		  d2h_time = 0, close_time = 0, total_time = 0;
#endif

#ifdef  TIMING
    gettimeofday(&tv_total_start, NULL);
#endif

#ifdef  TIMING
	gettimeofday(&tv_init_end, NULL);
	tvsub(&tv_init_end, &tv_total_start, &tv);
	init_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

#ifdef  TIMING
	gettimeofday(&tv_mem_alloc_end, NULL);
	tvsub(&tv_mem_alloc_end, &tv_init_end, &tv);
	mem_alloc_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

	size_t local_work_size = 1024 > order ? order : 1024;
	size_t global_work_size = count * local_work_size;

	printf("# of blocks = %d, # of threads/block = %d (ensure that device can handle)\n", (int)(global_work_size/local_work_size), (int)local_work_size);

#pragma omp parallel
{
	int thid = omp_get_thread_num();
	int bid = thid / local_work_size;
	int local_id = thid % local_work_size;

	if (bid < count) {

		long local_currKnode = currKnode[bid];
		long local_offset = offset[bid];
		int local_key = keys[bid];

		int i;
		for(i = 0; i < maxheight; i++){

			if((knodes[local_currKnode].keys[local_id] <= local_key) && (knodes[local_currKnode].keys[local_id+1] > local_key)){

				if(knodes[local_offset].indices[local_id] < knodes_elem){
					local_offset = knodes[local_offset].indices[local_id];
				}
			}

#pragma omp barrier

			if(0 == local_id){
				local_currKnode = local_offset;
			}

#pragma omp barrier

		}

		if(knodes[local_currKnode].keys[local_id] == local_key){
			ans[bid].value = records[knodes[local_currKnode].indices[local_id]].value;
		}
	}
}

#ifdef  TIMING
	gettimeofday(&tv_close_start, NULL);
#endif

#ifdef  TIMING
	gettimeofday(&tv_close_end, NULL);
	tvsub(&tv_close_end, &tv_close_start, &tv);
	close_time += tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
    tvsub(&tv_close_end, &tv_total_start, &tv);
    total_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

#ifdef TIMING
	printf("Time spent in different stages of GPU_CUDA KERNEL:\n");
	printf("Init: %f\n", init_time);
	printf("MemAlloc: %f\n", mem_alloc_time);
	printf("HtoD: %f\n", h2d_time);
	printf("Exec: %f\n", kernel_time);
	printf("DtoH: %f\n", d2h_time);
	printf("Close: %f\n", close_time);
	printf("Total: %f\n", total_time);
#endif

}

